struct GoogleMapViewRepresentable: UIViewRepresentable {
    @Binding var selectedCoordinate: CLLocationCoordinate2D
    @Binding var selectedAddress: String
    @Binding var zoom: Float

    func makeCoordinator() -> Coordinator {
        Coordinator(self)
    }

    func makeUIView(context: Context) -> GMSMapView {
        let camera = GMSCameraPosition.camera(withLatitude: selectedCoordinate.latitude,
                                              longitude: selectedCoordinate.longitude,
                                              zoom: zoom)
        let mapView = GMSMapView(frame: .zero, camera: camera)
        mapView.settings.compassButton = true
        mapView.settings.myLocationButton = true
        mapView.isMyLocationEnabled = true
        mapView.delegate = context.coordinator

        context.coordinator.marker.position = selectedCoordinate
        context.coordinator.marker.title = "Selected"
        context.coordinator.marker.map = mapView

        return mapView
    }

    func updateUIView(_ uiView: GMSMapView, context: Context) {
        let currentZoom = uiView.camera.zoom
        if abs(currentZoom - zoom) >= 0.5 {
            uiView.animate(toZoom: zoom)
        }

        let markerPos = context.coordinator.marker.position
        if markerPos.latitude != selectedCoordinate.latitude || markerPos.longitude != selectedCoordinate.longitude {
            context.coordinator.marker.position = selectedCoordinate
            uiView.animate(toLocation: selectedCoordinate)
        }
    }

    final class Coordinator: NSObject, GMSMapViewDelegate {
        let parent: GoogleMapViewRepresentable
        let marker = GMSMarker()
        private let geocoder = GMSGeocoder()

        init(_ parent: GoogleMapViewRepresentable) {
            self.parent = parent
        }

        func mapView(_ mapView: GMSMapView, didTapAt coordinate: CLLocationCoordinate2D) {
            parent.selectedCoordinate = coordinate
            marker.position = coordinate
            marker.title = "Selected"
            marker.snippet = "Lat \(coordinate.latitude), Lng \(coordinate.longitude)"
            marker.map = mapView

            geocoder.reverseGeocodeCoordinate(coordinate) { [weak self] response, error in
                guard let self else { return }
                if let error {
                    DispatchQueue.main.async {
                        self.parent.selectedAddress = "Reverse geocode error: \(error.localizedDescription)"
                    }
                    return
                }
                if let result = response?.firstResult(), let lines = result.lines, !lines.isEmpty {
                    DispatchQueue.main.async {
                        self.parent.selectedAddress = lines.joined(separator: ", ")
                    }
                } else {
                    DispatchQueue.main.async {
                        self.parent.selectedAddress = "Lat \(coordinate.latitude), Lng \(coordinate.longitude)"
                    }
                }
            }
        }

        func mapView(_ mapView: GMSMapView, idleAt position: GMSCameraPosition) {
            DispatchQueue.main.async {
                self.parent.zoom = position.zoom
            }
        }
    }
}

