final class PaymentsViewModel: ObservableObject {
    @Published var amountDollars: Double = 10
    @Published var statusText: String = "Ready"
    @Published var isProcessing: Bool = false
    @Published var showingSheet: Bool = false

    var paymentSheet: PaymentSheet?
    var onCompletion: ((PaymentSheetResult) -> Void)?

    var amountDisplay: String {
        let formatter = NumberFormatter()
        formatter.numberStyle = .currency
        formatter.currencyCode = "USD"
        return formatter.string(from: NSNumber(value: amountDollars)) ?? "$\(Int(amountDollars))"
    }

    func presentDemoPayment() {
        isProcessing = true
        statusText = "Preparing demo checkout…"

        DispatchQueue.main.asyncAfter(deadline: .now() + 0.6) {
            self.isProcessing = false
            self.statusText = "Demo mode: PaymentSheet requires a backend-created PaymentIntent client secret. Replace DemoPaymentIntentProvider with your server integration."
            self.configurePaymentSheetIfPossible()
            self.showingSheet = true
        }
    }

    private func configurePaymentSheetIfPossible() {
        let demo = DemoPaymentIntentProvider.shared

        if let clientSecret = demo.clientSecret {
            var config = PaymentSheet.Configuration()
            config.merchantDisplayName = "Investor Demo"
            config.allowsDelayedPaymentMethods = true
            self.paymentSheet = PaymentSheet(paymentIntentClientSecret: clientSecret, configuration: config)
            self.onCompletion = { [weak self] result in
                guard let self else { return }
                switch result {
                case .completed:
                    self.statusText = "Payment completed (test)."
                case .canceled:
                    self.statusText = "Payment canceled."
                case .failed(let error):
                    self.statusText = "Payment failed: \(error.localizedDescription)"
                }
                self.showingSheet = false
            }
        } else {
            self.paymentSheet = nil
            self.onCompletion = { [weak self] _ in
                self?.showingSheet = false
            }
        }
    }
}

final class DemoPaymentIntentProvider {
    static let shared = DemoPaymentIntentProvider()

    let clientSecret: String? = nil

    private init() {}
}

