final class PaymentSheetHostViewController: UIViewController {
    private let paymentSheet: PaymentSheet?
    private let onCompletion: ((PaymentSheetResult) -> Void)?

    init(paymentSheet: PaymentSheet?, onCompletion: ((PaymentSheetResult) -> Void)?) {
        self.paymentSheet = paymentSheet
        self.onCompletion = onCompletion
        super.init(nibName: nil, bundle: nil)
        modalPresentationStyle = .pageSheet
    }

    required init?(coder: NSCoder) { fatalError("init(coder:) has not been implemented") }

    override func viewDidAppear(_ animated: Bool) {
        super.viewDidAppear(animated)

        guard let paymentSheet else {
            let alert = UIAlertController(
                title: "Backend Required",
                message: "To present Stripe PaymentSheet, you must create a PaymentIntent on your server and provide its client secret.\n\nThis demo app is wired with the publishable key, but does not include a backend.\n\nSet DemoPaymentIntentProvider.shared.clientSecret to a valid test client secret to demo the full flow.",
                preferredStyle: .alert
            )
            alert.addAction(UIAlertAction(title: "OK", style: .default) { _ in
                self.dismiss(animated: true)
            })
            present(alert, animated: true)
            return
        }

        paymentSheet.present(from: self) { result in
            self.onCompletion?(result)
        }
    }
}

